try {
  const items = $input.all();
  const campaign = $node['Split In Batches'].json;
  const perfData = items.map(i => i.json);

  let totalFreq = 0, totalCtr = 0, freqCount = 0, ctrCount = 0;
  for (const p of perfData) {
    if (p.frequency !== undefined && p.frequency !== null) { totalFreq += parseFloat(p.frequency); freqCount++; }
    if (p.ctr !== undefined && p.ctr !== null) { totalCtr += parseFloat(p.ctr); ctrCount++; }
  }
  const avgFreq = freqCount > 0 ? totalFreq / freqCount : 0;
  const avgCtr = ctrCount > 0 ? totalCtr / ctrCount : 1;

  return [{
    json: {
      campaign_id: campaign.id,
      campaign_name: campaign.campaign_name || '',
      business_id: campaign.business_id || '',
      email: campaign.business_email || '',
      avg_frequency: parseFloat(avgFreq.toFixed(2)),
      avg_ctr: parseFloat(avgCtr.toFixed(2)),
      needs_refresh: avgFreq > 2.5 || avgCtr < 0.5,
      refresh_reason: avgFreq > 2.5 ? 'high_frequency' : (avgCtr < 0.5 ? 'low_ctr' : 'none'),
      data_points: perfData.length
    }
  }];
} catch(e) {
  return [{json: {error: e.message, needs_refresh: false, campaign_id: $node['Split In Batches'].json.id}}];
}

