try {
  const items = $input.all();
  const results = [];
  for (const item of items) {
    let parsed;
    try {
      const text = item.json.content[0].text;
      parsed = JSON.parse(text);
    } catch(e) {
      const text = item.json.content[0].text;
      const match = text.match(/\{[\s\S]*\}/);
      parsed = match ? JSON.parse(match[0]) : {variants: []};
    }
    results.push({json: {
      campaign_id: $node['Check Creative Metrics'].json.campaign_id,
      campaign_name: $node['Check Creative Metrics'].json.campaign_name,
      email: $node['Check Creative Metrics'].json.email,
      avg_frequency: $node['Check Creative Metrics'].json.avg_frequency,
      avg_ctr: $node['Check Creative Metrics'].json.avg_ctr,
      refresh_reason: $node['Check Creative Metrics'].json.refresh_reason,
      variants: parsed.variants || []
    }});
  }
  return results;
} catch(e) {
  return [{json: {error: e.message, variants: []}}];
}
